import torch
import torch.nn as nn
import timm


class ImageClassifier(nn.Module):
    def __init__(self, model_name='convnext_tiny.fb_in22k_ft_in1k', num_classes=100, drop_rate=0.2):
        super().__init__()
        self.model_name = model_name
        self.num_classes = num_classes
        self.drop_rate = drop_rate
        self.backbone = timm.create_model(
            model_name,
            pretrained=True,
            num_classes=num_classes,
            drop_rate=drop_rate,
        )

    def forward(self, x):
        return self.backbone(x)


def create_model(model_name='convnext_tiny.fb_in22k_ft_in1k', num_classes=100, drop_rate=0.2):
    return ImageClassifier(model_name=model_name, num_classes=num_classes, drop_rate=drop_rate)
